/// Return the minimum generated SIS rank that supports `width`.
pub fn min_rank_for_secure_width(d: u32, collision_inf: u32, width: u64) -> Option<usize> {
    let widths = sis_max_widths(d, collision_inf)?;
    for (i, &max_w) in widths.iter().enumerate() {
        if width <= max_w {
            return Some(i + 1);
        }
    }
    None
}

/// Round `collision_inf` up to the next generated collision bucket.
pub fn ceil_supported_collision(d: u32, collision_inf: u32) -> Option<u32> {
    const D32: &[u32] = &[
        2, 3, 7, 15, 31, 63, 127, 255, 511, 1023, 2047, 4095, 8191, 16383, 32767, 65535, 131071,
        262143,
    ];
    const D64: &[u32] = &[
        2, 3, 7, 15, 31, 63, 127, 255, 511, 1023, 2047, 4095, 8191, 16383, 32767,
    ];
    const D128: &[u32] = &[2, 3, 7, 15, 31, 63, 255, 511, 1023, 2047, 4095, 8191];
    let buckets = match d {
        32 => D32,
        64 => D64,
        128 => D128,
        _ => return None,
    };
    buckets
        .iter()
        .copied()
        .find(|&bucket| collision_inf <= bucket)
}
